// Extension function on String
fun String.isPalindrome(): Boolean {
    return this == this.reversed()
}

println("racecar".isPalindrome()) // true
println("hello".isPalindrome())   // false

// Lambda
val square = { x: Int -> x * x }
println(square(5)) // 25
